document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelectorAll(".ebhdr3-nav-dropdown");e.forEach(n=>{const t=n.querySelector(".nav-services-btn");t.addEventListener("click",o=>{if(window.innerWidth<790){o.preventDefault();const t=n.classList.contains("open");e.forEach(e=>e.classList.remove("open")),t||n.classList.add("open")}else t.dataset.href&&(window.location.href=t.dataset.href)})}),document.addEventListener("click",e=>{e.target.closest(".ebhdr3-nav-dropdown")||document.querySelectorAll(".ebhdr3-nav-dropdown").forEach(e=>e.classList.remove("open"))})});